const input = $input.first().json;

const tipo = (input.tipo || input.body?.tipo || 'lead_qualificado').toLowerCase();
const nome = input.nome || input.body?.nome || 'Não informado';
const whatsapp = input.whatsapp || input.body?.whatsapp || 'Não informado';
const destinos = input.destinos || input.body?.destinos || 'Não informado';
const numViajantes = input.num_viajantes || input.body?.num_viajantes || '0';
const numCriancas = input.num_criancas || input.body?.num_criancas || '0';
const idadesCriancas = input.idades_criancas || input.body?.idades_criancas || '';

// Montar string de viajantes com crianças
let viajantesStr = `${numViajantes} adulto(s)`;
if (numCriancas && numCriancas !== '0') {
  viajantesStr += ` + ${numCriancas} criança(s)`;
  if (idadesCriancas) {
    viajantesStr += ` (${idadesCriancas} anos)`;
  }
}

const destinatario = '5551990119605';

return [{
  json: {
    destinatario,
    nome_lead: nome,
    destinos: destinos,
    whatsapp_lead: whatsapp,
    viajantes: viajantesStr,
    tipo,
    sucesso: true
  }
}];
